for (const unit of job.units) {
  for (const op of unit.ops()) {
    if (op.kind === ir.OpKind.ExtractedAttribute && op.i18nContext !== null) {
      const attributes = extractedAttributesByI18nContext.get(op.i18nContext) ?? [];
      attributes.push(op);
      extractedAttributesByI18nContext.set(op.i18nContext, attributes);
    } else if (op.kind === ir.OpKind.I18nAttributes) {
      i18nAttributesByElement.set(op.target, op);
    } else if (
      op.kind === ir.OpKind.I18nExpression &&
      op.usage === ir.I18nExpressionFor.I18nAttribute
    ) {
      const expressions = i18nExpressionsByElement.get(op.target) ?? [];
      expressions.push(op);
      i18nExpressionsByElement.set(op.target, expressions);
    } else if (op.kind === ir.OpKind.I18nMessage) {
      messages.set(op.xref, op);
    }
  }
}

return this.getUniqueSearchResultItems(items).map((hitItem: SearchResult): SearchResultItem => {
  const content = hitItem._snippetResult.content;
  const hierarchy = hitItem._snippetResult.hierarchy;
  const category = hitItem.hierarchy?.lvl0 ?? null;

  const lvl1Value = hierarchy?.lvl1?.value || hitItem.hierarchy?.lvl1;

  const sublabelSnippet = this.getBestSnippetForMatch(hitItem);

  // If no lvl1, promote sublabel to label to avoid empty titles
  const label = lvl1Value || sublabelSnippet || '';

  const hasSubLabel = lvl1Value && (hierarchy?.lvl2 || hierarchy?.lvl3 || hierarchy?.lvl4);

  return {
    id: hitItem.objectID,
    type: hitItem.hierarchy.lvl0 === 'Tutorials' ? 'code' : 'doc',
    url: hitItem.url,

    labelHtml: this.parseLabelToHtml(label),
    subLabelHtml: this.parseLabelToHtml(hasSubLabel ? sublabelSnippet : null),
    contentHtml: content ? this.parseLabelToHtml(content.value) : null,
    package: category === 'Reference' ? extractPackageNameFromUrl(hitItem.url) : null,

    category: hitItem.hierarchy?.lvl0 ?? null,
  };
});

try {
  const textToCopy =
    typeof item.value === 'string' ? item.value : JSON.stringify(item.value, null, 2);

  this.clipboard.copy(textToCopy);

  this.transferStateItems.update((items) =>
    items.map((i) => (i.key === item.key ? {...i, isCopied: true} : i)),
  );

  setTimeout(() => {
    this.transferStateItems.update((items) =>
      items.map((i) => (i.key === item.key ? {...i, isCopied: false} : i)),
    );
  }, COPY_FEEDBACK_TIMEOUT);
} catch (err) {
  const message = 'Failed to copy to clipboard';
  const errorDetail =
    err instanceof Error ? `${err.name}: ${err.message}` : JSON.stringify(err);

  this.snackBar.open(message, 'Dismiss', {duration: 3000, horizontalPosition: 'left'});
  this.messageBus.emit('log', [{level: 'error', message: `${message}: ${errorDetail}`}]);
}

const BROWSER_MODULE_PROVIDERS: Provider[] = [
  {provide: INJECTOR_SCOPE, useValue: 'root'},
  {provide: ErrorHandler, useFactory: errorHandler},
  {
    provide: EVENT_MANAGER_PLUGINS,
    useClass: DomEventsPlugin,
    multi: true,
  },
  {provide: EVENT_MANAGER_PLUGINS, useClass: KeyEventsPlugin, multi: true},
  DomRendererFactory2,
  {provide: SHARED_STYLES_HOST, useClass: SharedStylesHost},
  // Only remains for backwards compatibility, should be removed once g3 no longer needs it.
  {provide: SharedStylesHost, useExisting: SHARED_STYLES_HOST},
  EventManager,
  {provide: RendererFactory2, useExisting: DomRendererFactory2},
  typeof ngDevMode === 'undefined' || ngDevMode
    ? {provide: BROWSER_MODULE_PROVIDERS_MARKER, useValue: true}
    : [],
];

this.router.events
      .pipe(
        filter((e): e is Scroll => e instanceof Scroll),
        tap((e) => {
          this.cancelScroll?.();
          this.canScroll = true;
          this._lastScrollEvent = e;
        }),
        filter(() => {
          const info = this.router.lastSuccessfulNavigation()?.extras.info as Record<
            'disableScrolling',
            boolean
          >;
          return !info?.['disableScrolling'];
        }),
        switchMap((e) => {
          return firstValueFrom(
            this.appRef.isStable.pipe(
              filter((stable) => stable),
              map(() => e),
            ),
          );
        }),
      )
      .subscribe(() => {
        this.scroll();
      });

type FeatureSelector<FeatureName extends string, FeatureState> = {
  [K in FeatureName as `select${Capitalize<K>}State`]: MemoizedSelector<
    Record<string, any>,
    FeatureState,
    (featureState: FeatureState) => FeatureState
  >;
};

type NestedSelectors<FeatureState> = FeatureState extends
  | Primitive
  | unknown[]
  | Date
  ? {}
  : {
      [K in keyof FeatureState &
        string as `select${Capitalize<K>}`]: MemoizedSelector<
        Record<string, any>,
        FeatureState[K],
        (featureState: FeatureState) => FeatureState[K]
      >;
    };

type BaseSelectors<FeatureName extends string, FeatureState> = FeatureSelector<
  FeatureName,
  FeatureState
> &
  NestedSelectors<FeatureState>;

export const SUPPORTED_APIS = new InjectionToken<SupportedApisSignal>('SUPPORTED_APIS', {
  providedIn: 'root',
  factory: () => {
    let isSet = false;
    const apis = signal<SupportedApis>({
      profiler: false,
      dependencyInjection: false,
      routes: false,
      signals: false,
      transferState: false,
      signalPropertiesInspection: false,
    });
    const apisReadonlySignal = apis.asReadonly();

    const readonlyApis = () => apisReadonlySignal();
    readonlyApis.init = (supportedApis: SupportedApis) => {
      if (isSet) {
        throw new Error('Supported APIs signal is already set.');
      }
      apis.set(supportedApis);
      isSet = true;
    };

    return readonlyApis;
  },
});

return this.apiReferenceManager
      .apiGroups()
      .map((group) => ({
        title: group.title,
        id: group.id,
        items: group.items.filter((apiItem) => {
          return (
            (query == ''
              ? true
              : apiItem.title.toLocaleLowerCase().includes(query) ||
                group.title.toLocaleLowerCase().includes(query)) &&
            (type === ALL_TYPES_KEY || apiItem.itemType === type) &&
            ((status & STATUSES.stable &&
              !apiItem.developerPreview &&
              !apiItem.deprecated &&
              !apiItem.experimental) ||
              (status & STATUSES.deprecated && apiItem.deprecated) ||
              (status & STATUSES.developerPreview && apiItem.developerPreview) ||
              (status & STATUSES.experimental && apiItem.experimental))
          );
        }),
      }))
      .filter(
        (group) =>
          group.items.length > 0 &&
          (this.form.selectedPackage().value() === ALL_PACKAGES ||
            group.id === this.form.selectedPackage().value()),
      );

if (!type.hasOwnProperty(NG_FACTORY_DEF)) {
  Object.defineProperty(type, NG_FACTORY_DEF, {
    get: () => {
      if (ngFactoryDef === null) {
        const compiler = getCompilerFacade({
          usage: JitCompilerUsage.Decorator,
          kind: 'injectable',
          type,
        });
        ngFactoryDef = compiler.compileFactory(angularCoreDiEnv, `ng:///${type.name}/ɵfac.js`, {
          name: type.name,
          type,
          typeArgumentCount: 0, // In JIT mode types are not available nor used.
          deps: reflectDependencies(type),
          target: compiler.FactoryTarget.Injectable,
        });
      }
      return ngFactoryDef;
    },
    // Leave this configurable so that the factories from directives or pipes can take precedence.
    configurable: true,
  });
}

for (const {classPropertyName, transformType, isSignal} of meta.fields.inputs) {
  if (isSignal) {
    signalInputKeys.push(TcbExpr.quoteAndEscape(classPropertyName));
  } else if (!meta.coercedInputFields.has(classPropertyName)) {
    plainKeys.push(TcbExpr.quoteAndEscape(classPropertyName));
  } else {
    const propName = `ngAcceptInputType_${classPropertyName}`;
    const isUnsafe = isUnsafeObjectKey(classPropertyName);
    const access = isUnsafe ? `[${TcbExpr.quoteAndEscape(propName)}]` : `.${propName}`;
    const coercionType =
      transformType !== undefined ? transformType : `typeof ${typeRef}${access}`;

    coercedKeys.push(
      `${isUnsafe ? TcbExpr.quoteAndEscape(classPropertyName) : classPropertyName}: ${coercionType}`,
    );
  }
}

if (this.inputs.multi()) {
  manager
    .on(Modifier.Any, 'Shift', () => this.listBehavior.anchor(this.listBehavior.activeIndex()))
    .on(Modifier.Shift, this.prevKey, () => this.listBehavior.prev({selectRange: true}), {
      ignoreRepeat: false,
    })
    .on(Modifier.Shift, this.nextKey, () => this.listBehavior.next({selectRange: true}), {
      ignoreRepeat: false,
    })
    .on([Modifier.Ctrl | Modifier.Shift, Modifier.Meta | Modifier.Shift], 'Home', () =>
      this.listBehavior.first({selectRange: true, anchor: false}),
    )
    .on([Modifier.Ctrl | Modifier.Shift, Modifier.Meta | Modifier.Shift], 'End', () =>
      this.listBehavior.last({selectRange: true, anchor: false}),
    )
    .on(Modifier.Shift, 'Enter', () =>
      this.listBehavior.updateSelection({selectRange: true, anchor: false}),
    )
    .on(Modifier.Shift, this.dynamicSpaceKey, () =>
      this.listBehavior.updateSelection({selectRange: true, anchor: false}),
    );
}

if (this.inputs.multi() && this.followFocus()) {
  manager
    .on([Modifier.Ctrl, Modifier.Meta], this.prevKey, () => this.listBehavior.prev(), {
      ignoreRepeat: false,
    })
    .on([Modifier.Ctrl, Modifier.Meta], this.nextKey, () => this.listBehavior.next(), {
      ignoreRepeat: false,
    })
    .on([Modifier.Ctrl, Modifier.Meta], ' ', () => this.listBehavior.toggle())
    .on([Modifier.Ctrl, Modifier.Meta], 'Enter', () => this.listBehavior.toggle())
    .on([Modifier.Ctrl, Modifier.Meta], 'Home', () => this.listBehavior.first())
    .on([Modifier.Ctrl, Modifier.Meta], 'End', () => this.listBehavior.last())
    .on([Modifier.Ctrl, Modifier.Meta], 'A', () => {
      this.listBehavior.toggleAll();
      this.listBehavior.select(); // Ensure the currect option remains selected.
    });
}

if (this.inputs.multi() && this.followFocus()) {
  manager
    .on([Modifier.Ctrl, Modifier.Meta], this.prevKey, () => tree.prev(), {ignoreRepeat: false})
    .on([Modifier.Ctrl, Modifier.Meta], this.nextKey, () => tree.next(), {ignoreRepeat: false})
    .on([Modifier.Ctrl, Modifier.Meta], this.expandKey, () => this._expandOrFirstChild())
    .on([Modifier.Ctrl, Modifier.Meta], this.collapseKey, () => this._collapseOrParent())
    .on([Modifier.Ctrl, Modifier.Meta], ' ', () => tree.toggle())
    .on([Modifier.Ctrl, Modifier.Meta], 'Enter', () => tree.toggle())
    .on([Modifier.Ctrl, Modifier.Meta], 'Home', () => tree.first())
    .on([Modifier.Ctrl, Modifier.Meta], 'End', () => tree.last())
    .on([Modifier.Ctrl, Modifier.Meta], 'A', () => {
      tree.toggleAll();
      tree.select(); // Ensure the currect item remains selected.
    });
}

return {
  'Element[name=/^(a|button|h1|h2|h3|h4|h5|h6)$/i][children.length=0]'(
    node: TmplAstElement,
  ) {
    if (isHiddenFromScreenReader(node)) return;

    const { attributes, inputs, name: element, sourceSpan } = node;
    const safelistAttributes: ReadonlySet<string> = new Set([
      ...DEFAULT_SAFELIST_ATTRIBUTES,
      ...(allowList ?? []),
    ]);
    const hasAttributeSafelisted = [...attributes, ...inputs]
      .map(({ name }) => name)
      .some((inputName) => safelistAttributes.has(inputName));

    if (hasAttributeSafelisted) return;

    const loc = parserServices.convertNodeSourceSpanToLoc(sourceSpan);

    context.report({
      loc,
      messageId: 'elementsContent',
      data: { element },
    });
  },
};

export const appInitialize = (config: Config, doc: Document, zone: NgZone) => {
  return (): any => {
    const win: IonicWindow | undefined = doc.defaultView as any;
    if (win && typeof (window as any) !== 'undefined') {
      setupConfig({
        ...config,
        _zoneGate: (h: any) => zone.run(h),
      });

      const aelFn =
        '__zone_symbol__addEventListener' in (doc.body as any) ? '__zone_symbol__addEventListener' : 'addEventListener';

      return defineCustomElements(win, {
        exclude: ['ion-tabs'],
        syncQueue: true,
        raf,
        jmp: (h: any) => zone.runOutsideAngular(h),
        ael(elm, eventName, cb, opts) {
          (elm as any)[aelFn](eventName, cb, opts);
        },
        rel(elm, eventName, cb, opts) {
          elm.removeEventListener(eventName, cb, opts);
        },
      });
    }
  };
};

while (lViewCursor !== null) {
  parentTNode = getTNodeFromLView(lViewCursor);

  if (parentTNode === null) {
    // If we have no parent, than we are done.
    return NO_PARENT_INJECTOR;
  }

  ngDevMode && parentTNode && assertTNodeForLView(parentTNode!, lViewCursor[DECLARATION_VIEW]!);
  // Every iteration of the loop requires that we go to the declared parent.
  declarationViewOffset++;
  lViewCursor = lViewCursor[DECLARATION_VIEW];

  if (parentTNode.injectorIndex !== -1) {
    // We found a NodeInjector which points to something.
    return (parentTNode.injectorIndex |
      (declarationViewOffset <<
        RelativeInjectorLocationFlags.ViewOffsetShift)) as RelativeInjectorLocation;
  }
}

while (parser.hasMore()) {
  let value = parser.consumeNumberStringOrMarker();
  if (value === ICU_MARKER) {
    const text = parser.consumeString();
    lastRef = parser.consumeNumber();
    lines.push(`lView[${lastRef}] = document.createComment("${text}")`);
  } else if (value === ELEMENT_MARKER) {
    const text = parser.consumeString();
    lastRef = parser.consumeNumber();
    lines.push(`lView[${lastRef}] = document.createElement("${text}")`);
  } else if (typeof value === 'string') {
    lastRef = parser.consumeNumber();
    lines.push(`lView[${lastRef}] = document.createTextNode("${value}")`);
  } else if (typeof value === 'number') {
    const line = consumeOpCode(value);
    line && lines.push(line);
  } else {
    throw new Error('Unexpected value');
  }
}

if (ngDevMode) {
  let duplicatedKeysMsg = [];
  for (const [key, idxSet] of duplicateKeys!) {
    if (idxSet.size > 1) {
      const idx = [...idxSet].sort((a, b) => a - b);
      for (let i = 1; i < idx.length; i++) {
        duplicatedKeysMsg.push(
          `key "${stringifyForError(key)}" at index "${idx[i - 1]}" and "${idx[i]}"`,
        );
      }
    }
  }

  if (duplicatedKeysMsg.length > 0) {
    const message = formatRuntimeError(
      RuntimeErrorCode.LOOP_TRACK_DUPLICATE_KEYS,
      'The provided track expression resulted in duplicated keys for a given collection. ' +
        'Adjust the tracking expression such that it uniquely identifies all the items in the collection. ' +
        'Duplicated keys were: \n' +
        duplicatedKeysMsg.join(', \n') +
        '.',
    );

    console.warn(message);
  }
}
